 // Importando a lógica

'use client';
import React, { useState, useEffect } from 'react';
import { buscarOfertasPromocao } from "./ofertasService";
import '../App.css';

export default function Topo({ totalItens, abrirCarrinho, verHistorico, usuarioLogado, setProdutos }) {
  const [tempo, setTempo] = useState(86400); // 24 horas

  // Lógica do Timer
  useEffect(() => {
    const timer = setInterval(() => {
      setTempo(prev => (prev > 0 ? prev - 1 : 86400));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const formatarTempo = (segundos) => {
    const h = Math.floor(segundos / 3600);
    const m = Math.floor((segundos % 3600) / 60);
    const s = segundos % 60;
    const format = (num) => String(num).padStart(2, '0');
    return `${format(h)}h ${format(m)}m ${format(s)}s`;
  };

  // Lógica para carregar a VIEW do MySQL
const lidarComOfertas = async () => {
  console.log("Iniciando busca de ofertas...");
  const ofertas = await buscarOfertasPromocao();
  
  // ABRA O F12 E VEJA O QUE APARECE AQUI:
  console.log("Conteúdo da variável ofertas:", ofertas);

  if (Array.isArray(ofertas) && ofertas.length > 0) {
    console.log("Sucesso! Atualizando vitrine com", ofertas.length, "itens.");
    setProdutos(ofertas);
  } else {
    console.error("A variável ofertas veio vazia ou não é um Array.");
    alert("O banco de dados não retornou produtos da VIEW promocao_10.");
  }
};

  return (
    <header className="topo-container">
      <div className="topo-esquerda">
        <img src="slog.png" alt="Logo" className="imagem-topo" />
        <h1 className="titulo-loja">Amigo do Bairro</h1>
      </div>

      <div className="topo-centro">
        <div className="balao-ofertas">
          <span className="texto-pisca">OFERTAS DA SEMANA</span>
          <span className="timer-destaque">🔥{formatarTempo(tempo)}🔥</span>
        </div>
      </div>

      <div className="header-actions">
        <button className="btn-promocao" onClick={lidarComOfertas}>
          🏷️ 10% OFF
        </button>

        <button onClick={abrirCarrinho} className="botao-carrinho">
          🛒 <span className="qtd-carrinho">{totalItens}</span>
        </button>

        <button 
  className="btn-historico" 
  onClick={verHistorico} 
  onDoubleClick={onLogout} // Se der dois cliques, ele desloga!
  title="Clique para ver pedidos | Dois cliques para sair"
  style={{cursor: 'pointer'}}
>
  {usuarioLogado ? `Olá, 👤${usuarioLogado.nome} (Sair)` : "📋 Meus Pedidos"}
</button>
      </div>
    </header>
  );
}
